  wd:Q979511 wdt:P1625 ?movie.
  ?movie wdt:P577 ?releaseDate.
  FILTER (year(?releaseDate) = 1980).
  ?movie wdt:P166 ?award.
  OPTIONAL { ?movie rdfs:label ?movieLabel }
  FILTER (lang(?movieLabel) = "en")
}

